Definition iff_not@{u v k | u <= k, v <= k}
  (A : Type@{u}) (B : Type@{v})
  : A <-> B -> iff@{u v k} (~A) (~B).

#[export] Instance contr_arrow {A B : Type} `{Contr B}
  : Contr (A -> B) | 100
  := contr_forall.

#[export] Instance istrunc_arrow {A B : Type} `{IsTrunc n B}
  : IsTrunc n (A -> B) | 100
  := istrunc_forall.

Instance decidable_arrow {A B : Type}
  `{Decidable A} `{Decidable B}
  : Decidable (A -> B).
